from enum import Enum
from typing import Dict, List, Optional, Any
from dataclasses import dataclass, field
from decimal import Decimal
from datetime import datetime


class UserTier(Enum):
    GUEST = "guest"
    STANDARD = "standard"
    PREMIUM = "premium"
    ADMIN = "admin"


class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"


@dataclass
class CartItem:
    product_id: str
    name: str
    price: Decimal
    quantity: int
    available_stock: int = 1000


@dataclass
class DiscountCode:
    code: str
    discount_type: DiscountType
    value: Decimal
    allowed_tiers: List[UserTier]
    minimum_purchase: Decimal = Decimal('0')
    active: bool = True


@dataclass
class User:
    user_id: str
    tier: UserTier
    email: str


@dataclass
class Address:
    country: str
    state: str
    zip_code: str


@dataclass
class PaymentInfo:
    method: str
    token: str


@dataclass
class CheckoutResult:
    success: bool
    order_id: Optional[str] = None
    total_amount: Optional[Decimal] = None
    error_message: Optional[str] = None
    details: Dict[str, Any] = field(default_factory=dict)


class CheckoutProcessor:
    def __init__(self, tax_rates: Dict[str, Decimal], discount_codes: Dict[str, DiscountCode]):
        self.tax_rates = tax_rates
        self.discount_codes = discount_codes
        self.processed_orders = {}
    
    def process_checkout(
        self,
        cart_items: List[CartItem],
        user: User,
        discount_code: Optional[str],
        shipping_address: Address,
        payment_info: PaymentInfo
    ) -> CheckoutResult:
        step1_result = self._validate_cart_items(cart_items)
        if not step1_result['valid']:
            return CheckoutResult(
                success=False,
                error_message=step1_result['error']
            )
        
        step2_result = self._apply_discount_code(
            cart_items=cart_items,
            subtotal=step1_result['subtotal'],
            discount_code=discount_code,
            user=user
        )
        if not step2_result['valid']:
            return CheckoutResult(
                success=False,
                error_message=step2_result['error']
            )
        
        step3_result = self._calculate_tax(
            subtotal_after_discount=step2_result['final_subtotal'],
            shipping_address=shipping_address
        )
        if not step3_result['valid']:
            return CheckoutResult(
                success=False,
                error_message=step3_result['error']
            )
        
        step4_result = self._process_payment(
            total_amount=step3_result['total'],
            payment_info=payment_info,
            user=user
        )
        if not step4_result['valid']:
            return CheckoutResult(
                success=False,
                error_message=step4_result['error']
            )
        
        step5_result = self._create_order_record(
            cart_items=cart_items,
            user=user,
            subtotal=step1_result['subtotal'],
            discount_amount=step2_result['discount_amount'],
            discount_code=discount_code,
            tax_amount=step3_result['tax_amount'],
            total=step3_result['total'],
            shipping_address=shipping_address,
            payment_info=payment_info,
            payment_transaction_id=step4_result['transaction_id']
        )
        
        return CheckoutResult(
            success=True,
            order_id=step5_result['order_id'],
            total_amount=step3_result['total'],
            details={
                'subtotal': step1_result['subtotal'],
                'discount_code': discount_code,
                'discount_amount': step2_result['discount_amount'],
                'subtotal_after_discount': step2_result['final_subtotal'],
                'tax_amount': step3_result['tax_amount'],
                'total': step3_result['total'],
                'payment_transaction_id': step4_result['transaction_id'],
                'order_id': step5_result['order_id']
            }
        )
    
    def _validate_cart_items(self, cart_items: List[CartItem]) -> Dict[str, Any]:
        if not cart_items:
            return {'valid': False, 'error': 'Cart is empty'}
        
        subtotal = Decimal('0')
        
        for item in cart_items:
            if item.quantity <= 0:
                return {
                    'valid': False,
                    'error': f'Invalid quantity for item {item.name}'
                }
            
            if item.price <= 0:
                return {
                    'valid': False,
                    'error': f'Invalid price for item {item.name}'
                }
            
            if item.quantity > item.available_stock:
                return {
                    'valid': False,
                    'error': f'Insufficient stock for item {item.name}. Available: {item.available_stock}'
                }
            
            subtotal += item.price * item.quantity
        
        return {
            'valid': True,
            'subtotal': subtotal
        }
    
    def _apply_discount_code(
        self,
        cart_items: List[CartItem],
        subtotal: Decimal,
        discount_code: Optional[str],
        user: User
    ) -> Dict[str, Any]:
        if not discount_code:
            return {
                'valid': True,
                'discount_amount': Decimal('0'),
                'final_subtotal': subtotal
            }
        
        if discount_code not in self.discount_codes:
            return {
                'valid': False,
                'error': f'Invalid discount code: {discount_code}'
            }
        
        discount = self.discount_codes[discount_code]
        
        if not discount.active:
            return {
                'valid': False,
                'error': f'Discount code {discount_code} is not active'
            }
        
        if user.tier not in discount.allowed_tiers:
            return {
                'valid': False,
                'error': f'User tier {user.tier.value} is not authorized to use discount code {discount_code}'
            }
        
        if subtotal < discount.minimum_purchase:
            return {
                'valid': False,
                'error': f'Minimum purchase of {discount.minimum_purchase} required for discount code {discount_code}'
            }
        
        if discount.discount_type == DiscountType.PERCENTAGE:
            discount_amount = subtotal * (discount.value / Decimal('100'))
        else:
            discount_amount = discount.value
        
        discount_amount = min(discount_amount, subtotal)
        
        final_subtotal = subtotal - discount_amount
        
        return {
            'valid': True,
            'discount_amount': discount_amount,
            'final_subtotal': final_subtotal
        }
    
    def _calculate_tax(
        self,
        subtotal_after_discount: Decimal,
        shipping_address: Address
    ) -> Dict[str, Any]:
        state_key = shipping_address.state.upper()
        
        if state_key not in self.tax_rates:
            return {
                'valid': False,
                'error': f'Tax rate not found for state: {shipping_address.state}'
            }
        
        tax_rate = self.tax_rates[state_key]
        tax_amount = subtotal_after_discount * tax_rate
        total = subtotal_after_discount + tax_amount
        
        return {
            'valid': True,
            'tax_amount': tax_amount,
            'tax_rate': tax_rate,
            'total': total
        }
    
    def _process_payment(
        self,
        total_amount: Decimal,
        payment_info: PaymentInfo,
        user: User
    ) -> Dict[str, Any]:
        if total_amount <= 0:
            return {
                'valid': False,
                'error': 'Invalid payment amount'
            }
        
        if not payment_info.token:
            return {
                'valid': False,
                'error': 'Payment token is required'
            }
        
        if payment_info.method not in ['credit_card', 'debit_card', 'paypal', 'bank_transfer']:
            return {
                'valid': False,
                'error': f'Invalid payment method: {payment_info.method}'
            }
        
        transaction_id = f'TXN-{user.user_id}-{datetime.now().timestamp()}'
        
        return {
            'valid': True,
            'transaction_id': transaction_id,
            'payment_method': payment_info.method
        }
    
    def _create_order_record(
        self,
        cart_items: List[CartItem],
        user: User,
        subtotal: Decimal,
        discount_amount: Decimal,
        discount_code: Optional[str],
        tax_amount: Decimal,
        total: Decimal,
        shipping_address: Address,
        payment_info: PaymentInfo,
        payment_transaction_id: str
    ) -> Dict[str, Any]:
        order_id = f'ORD-{user.user_id}-{len(self.processed_orders) + 1}-{int(datetime.now().timestamp())}'
        
        order_record = {
            'order_id': order_id,
            'user_id': user.user_id,
            'user_email': user.email,
            'user_tier': user.tier.value,
            'items': [
                {
                    'product_id': item.product_id,
                    'name': item.name,
                    'price': item.price,
                    'quantity': item.quantity
                }
                for item in cart_items
            ],
            'subtotal': subtotal,
            'discount_code': discount_code,
            'discount_amount': discount_amount,
            'tax_amount': tax_amount,
            'total': total,
            'shipping_address': {
                'country': shipping_address.country,
                'state': shipping_address.state,
                'zip_code': shipping_address.zip_code
            },
            'payment_method': payment_info.method,
            'payment_transaction_id': payment_transaction_id,
            'order_date': datetime.now().isoformat(),
            'status': 'completed'
        }
        
        self.processed_orders[order_id] = order_record
        
        return {
            'order_id': order_id,
            'order_record': order_record
        }


